body.script:
// Wacht tot de pagina volledig geladen is
window.onload = function() {
  // Initialiseer Google Identity Services
  google.accounts.id.initialize({
    client_id: '124658869788-55e9cll1e7d9ge3v1g8lgejhfr61teur.apps.googleusercontent.com',
    callback: handleLogin,
    auto_select: false,
    cancel_on_tap_outside: true
  });

  // Render de knop in de container
  google.accounts.id.renderButton(
    document.getElementById('google-btn-container'),
    {
      type: 'standard',
      shape: 'rectangular',
      theme: 'filled_black',
      text: 'signin_with',
      size: 'large',
      logo_alignment: 'left',
      width: 250
    }
  );

  // Optioneel: prompt weergeven (alleen als de gebruiker al eerder heeft ingelogd)
  // google.accounts.id.prompt();
};

// Callback functie voor succesvolle login
function handleLogin(response) {
  try {
    var payload = JSON.parse(atob(response.credential.split('.')[1]));
    var email = payload.email;
    var name = payload.name || email.split('@')[0];

    alert("Welcome " + name + "!\nEmail: " + email);

    // Sla gebruiker op in localStorage
    localStorage.setItem('arcade_user_email', email);
    localStorage.setItem('arcade_user_name', name);
    localStorage.setItem('arcade_user_pic', payload.picture || '');

    // Stuur door naar je game hub (verander deze URL!)
    // window.location.href = "https://jouw-game-hub.nl";

  } catch (err) {
    console.error("Login error:", err);
    alert("Login mislukt. Probeer opnieuw.");
  }
}
